const body = $input.first().json.body;
const serverType = (body.server_type || 'nginx').toLowerCase();
const scanData = body.scan_results;

// Build the set of missing headers and their recommended values
const fixes = {};
const RECOMMENDED = {
  'content-security-policy': "default-src 'self'; script-src 'self'; style-src 'self' 'unsafe-inline'; img-src 'self' data:; font-src 'self'; object-src 'none'; base-uri 'self'; form-action 'self';",
  'strict-transport-security': 'max-age=31536000; includeSubDomains; preload',
  'x-frame-options': 'DENY',
  'x-content-type-options': 'nosniff',
  'referrer-policy': 'strict-origin-when-cross-origin',
  'permissions-policy': 'accelerometer=(), ambient-light-sensor=(), autoplay=(), battery=(), camera=(), geolocation=(), gyroscope=(), magnetometer=(), microphone=(), payment=(), usb=()'
};

if (scanData && scanData.headers) {
  for (const h of scanData.headers) {
    if (!h.present) {
      fixes[h.key] = RECOMMENDED[h.key];
    }
  }
} else {
  // If no scan data, generate full config with all recommended headers
  Object.assign(fixes, RECOMMENDED);
}

if (Object.keys(fixes).length === 0) {
  return [{ json: { config: '# All security headers are already present! No changes needed.', server_type: serverType, headers_added: 0 } }];
}

let config = '';

if (serverType === 'nginx') {
  config = '# Add these lines inside your server {} block in nginx.conf\n\n';
  for (const [key, value] of Object.entries(fixes)) {
    config += `add_header ${key} "${value}" always;\n`;
  }
  config += '\n# Then reload nginx:\n# sudo nginx -s reload';

} else if (serverType === 'apache') {
  config = '# Add these lines to your .htaccess or VirtualHost config\n\n';
  config += '<IfModule mod_headers.c>\n';
  for (const [key, value] of Object.entries(fixes)) {
    config += `    Header always set ${key} "${value}"\n`;
  }
  config += '</IfModule>\n';
  config += '\n# Then restart Apache:\n# sudo service apache2 restart';

} else if (serverType === 'vercel') {
  const headers = Object.entries(fixes).map(([key, value]) => ({ key, value }));
  const vercelConfig = {
    headers: [
      {
        source: '/(.*)',
        headers
      }
    ]
  };
  config = '// Add this to your vercel.json\n\n' + JSON.stringify(vercelConfig, null, 2);

} else if (serverType === 'netlify') {
  config = '# Add this to your netlify/_headers file\n\n';
  config += '/*\n';
  for (const [key, value] of Object.entries(fixes)) {
    config += `  ${key}: ${value}\n`;
  }

} else if (serverType === 'cloudflare') {
  config = '// Cloudflare Worker — add to your worker script\n\n';
  config += 'export default {\n';
  config += '  async fetch(request, env) {\n';
  config += '    const response = await fetch(request);\n';
  config += '    const newHeaders = new Headers(response.headers);\n';
  for (const [key, value] of Object.entries(fixes)) {
    config += `    newHeaders.set('${key}', '${value}');\n`;
  }
  config += '    return new Response(response.body, { status: response.status, headers: newHeaders });\n';
  config += '  }\n';
  config += '};';
} else {
  config = '# Generic HTTP Headers Config\n\n';
  for (const [key, value] of Object.entries(fixes)) {
    config += `${key}: ${value}\n`;
  }
}

return [{
  json: {
    server_type: serverType,
    config,
    headers_added: Object.keys(fixes).length,
    headers_list: Object.keys(fixes)
  }
}];
